20	    : t('No dedicated resources applied');
21	
22	  const onEditClick = () =>
23	    createModal(({ isOpen, onClose }) => (
24	      <DedicatedResourcesModal
25	        isOpen={isOpen}
26	        onClose={onClose}
27	        onSubmit={onSubmit}
28	        template={template}
29	      />
30	    ));
31	
32	  return (
33	    <VirtualMachineDescriptionItem
34	      descriptionData={dedicatedResourcesText}
35	      descriptionHeader={t('Dedicated resources')}
36	      isEdit={editable}
37	      onEditClick={onEditClick}
38	    />
39	  );
40	};
41	
42	export default DedicatedResources;

